#include <stdio.h>

int main() {
  int count = 1;
  while (count <= 5) {
    printf("Number: %d\n", count);
    count++;
  }
  return 0;
}
// Output:
// Number: 1
// Number: 2
// Number: 3
// Number: 4
// Number: 5

#include <stdio.h>

int main() {
  int count = 10;
  while (count >= 1) {
    printf("Countdown: %d\n", count);
    count--;
  }
  return 0;
}
// Output:
// Countdown: 10
// Countdown: 9
// Countdown: 8
// Countdown: 7
// Countdown: 6
// Countdown: 5
// Countdown: 4
// Countdown: 3
// Countdown: 2
// Countdown: 1

#include <stdio.h>

int main() {
  int num = 1;
  while (num <= 10) {
    if (num % 2 == 0) {
      printf("Even number: %d\n", num);
    }
    num++;
  }
  return 0;
}
// Output:
// Even number: 2
// Even number: 4
// Even number: 6
// Even number: 8
// Even number: 10

#include <stdio.h>

int main() {
  int sum = 0;
  int num = 1;
  while (sum < 20) {
    sum += num;
    printf("Sum after adding %d: %d\n", num, sum);
    num++;
  }
  return 0;
}
// Output:
// Sum after adding 1: 1
// Sum after adding 2: 3
// Sum after adding 3: 6
// Sum after adding 4: 10
// Sum after adding 5: 15
// Sum after adding 6: 21

#include <stdio.h>

int main() {
  int count = 1;
  while (count <= 5) {
    printf("This will run forever!\n");
  }
  return 0;
}
// Output: (Sonsuz təkrarlanar, icra etməyin!)

